# ============================================================
# 04_rq1_within_between_city_similarity.R
#
# Purpose:
# Compare sewage-transit Jaccard similarity for:
# 1. within-city pairs
# 2. between-city pairs
#
# This is a descriptive RQ1 analysis showing whether sewage and
# transit profiles from the same city are more similar than
# sewage-transit profiles from different cities.
#
# Input:
# Jaccard distance matrices generated by:
# 03_rq1_jaccard_pcoa_permanova.R
#
# Expected input files:
# results/rq1/ordination_stats/rq1_group_jaccard_distance_matrix.tsv
# results/rq1/ordination_stats/rq1_class_jaccard_distance_matrix.tsv
#
# Main outputs:
# results/rq1/within_between_similarity/
# ============================================================

