)

combined_summary_output <- file.path(
  output_dir,
  "rq1_combined_within_between_city_similarity_summary.tsv"
)

write.table(
  combined_plot_data,
  file = combined_plot_data_output,
  sep = "\t",
  quote = FALSE,
  row.names = FALSE
)

write.table(
  combined_summary,
  file = combined_summary_output,
  sep = "\t",
  quote = FALSE,
  row.names = FALSE
)

message(
  "\n============================================================"
)

message(
  "RQ1 within-city vs between-city similarity analysis completed."
)

message(
  "Combined outputs:"
)

message(combined_plot_data_output)
message(combined_summary_output)

message(
  "============================================================"
)
